def evaluate_scent(snippet, goals):
    # Simulate 'Information Scent' by looking for goal-terms in a snippet
    count = 0
    for g in goals:
        if g.lower() in snippet.lower():
            count += 1
    return round(count / len(goals), 2)

goals = ['Climate', 'Carbon', 'Emissions']
snip1 = "Weather patterns are changing worldwide."
snip2 = "How to reduce Carbon Emissions and fight Climate change."

print(f"Scent 1: {evaluate_scent(snip1, goals)}")
print(f"Scent 2: {evaluate_scent(snip2, goals)}")
